// --- Source ---
var ZBASE32 = 'ybndrfg8ejkmcpqxot1uwisza345h769';

function generateSource() {
  var s = '';
  for (var i = 0; i < 10; i++) s += ZBASE32[Math.floor(Math.random() * 32)];
  return s;
}

function initSource() {
  var query = location.search.replace(/^\?/, '');
  if (query) {
    try {
      var prev = localStorage.getItem('meditation-source');
      if (prev && prev !== query) {
        var queue = loadPostQueue();
        queue.push(buildPostPayload('changed', prev));
        savePostQueue(queue);
      }
      localStorage.setItem('meditation-source', query);
    } catch (e) {}
    return query;
  }
  try {
    var stored = localStorage.getItem('meditation-source');
    if (stored) return stored;
  } catch (e) {}
  var generated = generateSource();
  try { localStorage.setItem('meditation-source', generated); } catch (e) {}
  return generated;
}

var appSource = initSource();

// --- Init ---
var PRECACHE_ASSETS = [
  'manifest.json',
  'sand.jpg',
  'sea.jpg',
  'icon-192.png',
  'icon-512.png',
  'favicon.svg',
  'NoSleep.min.js'
].concat(SOUND_OPTIONS.map(function (o) { return o.file; }));

Promise.all(PRECACHE_ASSETS.map(function (url) {
  return fetch(url).catch(function () {});
})).then(function () {
  document.getElementById('loading-screen').classList.remove('active');
  document.getElementById('start-screen').classList.add('active');
  onStartScreenActivated();
  maybePromptForEmail();
});

loadSettings();
populateSoundSelects(loadSoundSettings());
cacheAllSounds();
loadVolume();
createSessionAudio();
validateInputs();
window.addEventListener('appinstalled', function () {
  var queue = loadPostQueue();
  queue.push(buildPostPayload('install', appSource));
  savePostQueue(queue);
  flushPostQueue();
});
flushPostQueue();
window.addEventListener('online', flushPostQueue);

// Register service worker uniformly across local and deployed environments.

